<template><div class="exam-manage"><div class="header"><h1>题库管理</h1><el-button type="primary" @click="create">新增题目</el-button></div><el-table :data="questions" v-loading="loading"><el-table-column prop="content" label="题目" min-width="280"/><el-table-column prop="courseName" label="课程" width="180"/><el-table-column prop="type" label="题型" width="100"/><el-table-column prop="knowledge" label="知识点" width="140"/><el-table-column prop="difficulty" label="难度" width="100"/><el-table-column label="操作" width="100"><template #default="{row}"><el-button type="danger" size="small" @click="remove(row)">删除</el-button></template></el-table-column></el-table></div></template>
<script setup>
import {onMounted,ref} from 'vue';import {ElMessage,ElMessageBox} from 'element-plus';import {createQuestion,deleteQuestion,getQuestionBank} from '../../api/admin.js';import {getCourseList} from '../../api/course.js';
const questions=ref([]),courses=ref([]),loading=ref(false);async function load(){loading.value=true;try{const d=await getQuestionBank({page:1,size:100});questions.value=d.records||[]}finally{loading.value=false}}async function create(){const {value:courseId}=await ElMessageBox.prompt(`请输入课程ID：${courses.value.slice(0,10).map(c=>`${c.courseId} ${c.courseName}`).join('；')}`,'选择课程');if(!courses.value.some(c=>c.courseId===courseId)){ElMessage.warning('课程ID不存在');return}const {value:content}=await ElMessageBox.prompt('请输入题目内容','新增题目');const {value:answer}=await ElMessageBox.prompt('请输入标准答案','新增题目');await createQuestion({courseId,type:'short',content,answer,score:10,difficulty:'medium',knowledge:'综合练习'});ElMessage.success('题目已创建');await load()}async function remove(row){await ElMessageBox.confirm('确定删除该题目吗？','提示',{type:'warning'});await deleteQuestion(row.id);await load()}onMounted(async()=>{const d=await getCourseList({page:1,size:100});courses.value=d.courses||[];await load()})
</script><style scoped>.exam-manage{background:#fff;padding:var(--spacing-xl);border-radius:var(--radius-xl)}.header{display:flex;align-items:center;justify-content:space-between;margin-bottom:var(--spacing-lg)}</style>
